	c := New(500, 5*time.Millisecond)
	defer c.Stop()

	var wg sync.WaitGroup
	const workers = 10
	const opsPerWorker = 200

	// Writers
	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for i := 0; i < opsPerWorker; i++ {
				key := fmt.Sprintf("w%d-k%d", id, i)
				c.Set(key, i, 50*time.Millisecond)
			}
		}(w)
	}

	// Readers
	for w := 0; w < workers; w++ {
		wg.Add(1)
