			defer wg.Done()
			for i := 0; i < opsPerWorker; i++ {
				key := fmt.Sprintf("w%d-k%d", id, i)
				c.Get(key)
			}
		}(w)
	}

	wg.Wait()

	// Verify stats are consistent: total operations = hits + misses + some evictions.
	stats := c.Stats()
	totalLookups := stats.Hits + stats.Misses
